                x={stampX + (STAMP_SIZE / 2)}
                y={stampY + (STAMP_SIZE / 2)}
                radius={(STAMP_SIZE / 2) + 1.8}
                fill="rgba(255,255,255,0.78)"
                shadowColor="rgba(0,0,0,0.22)"
                shadowBlur={5}
                shadowOffsetY={2}
                listening={false}
            />
            {emojiImage ? (
                <KonvaImage
                    x={stampX}
                    y={stampY}
                    width={STAMP_SIZE}
                    height={STAMP_SIZE}
                    image={emojiImage}
                    listening={false}
                />
            ) : (
                <Text
                    x={stampX}
                    y={stampY}
                    width={STAMP_SIZE}
                    height={STAMP_SIZE}
                    text={icon}
                    fontSize={STAMP_FONT_SIZE}
                    align="center"
                    verticalAlign="middle"
                    listening={false}
                />
            )}
            <Circle
                x={avatarCenterX}
                y={avatarCenterY}
                radius={avatarRadius + 1.2}
                fill="rgba(0,0,0,0.22)"
                listening={false}
            />
            {avatarImage ? (
                <Group
                    clipFunc={(ctx) => {
                        ctx.arc(avatarCenterX, avatarCenterY, avatarRadius, 0, Math.PI * 2, false);
                    }}
                    listening={false}
                >
                    <KonvaImage
                        x={avatarCenterX - avatarRadius}
                        y={avatarCenterY - avatarRadius}
                        width={PROFILE_SIZE}
                        height={PROFILE_SIZE}
                        image={avatarImage}
                        listening={false}
                    />
                </Group>
            ) : (
                <>
                    <Circle
                        x={avatarCenterX}
                        y={avatarCenterY}
                        radius={avatarRadius}
                        fill="#c9d0dc"
                        stroke="rgba(255,255,255,0.95)"
                        strokeWidth={0.7}
                        listening={false}
                    />
                    <Text
                        x={avatarCenterX - avatarRadius}
                        y={avatarCenterY - avatarRadius}
                        width={PROFILE_SIZE}
                        height={PROFILE_SIZE}
                        text={getNameInitial(stamp?.user_name)}
                        fontSize={8}
                        fontStyle="bold"
                        fill="#1f2c3f"
                        align="center"
                        verticalAlign="middle"
                        listening={false}
                    />
                </>
            )}
        </Group>
    );
};

